import{_ as t,o,c as n,ae as i}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Salesforce - Open App Default","description":"","frontmatter":{"title":"Salesforce - Open App Default","slug":"salesforce-open-app-default"},"headers":[],"relativePath":"marketer-hub/salesforce-open-app-default.md","filePath":"marketer-hub/salesforce-open-app-default.md"}'),a={name:"marketer-hub/salesforce-open-app-default.md"};function l(r,e,s,p,c,d){return o(),n("div",null,[...e[0]||(e[0]=[i(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Meet Email Studio. Reach your customers with the world’s #1 email marketing platform. Build smarter email — from basic marketing campaigns to sophisticated 1-to-1 messages.</p><h2 id="_1-complete-branch-email-prerequisites" tabindex="-1">1. Complete Branch Email Prerequisites <a class="header-anchor" href="#_1-complete-branch-email-prerequisites" aria-label="Permalink to &quot;1. Complete Branch Email Prerequisites&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">DEVELOPER MAY BE REQUIRED</p><p>The following Branch Email prerequisite includes providing URI schemes and other components that may require a developer:</p><ul><li><a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer"><strong>Add Deep Link Routing &amp; Required Redirects</strong></a></li></ul></div><div class="warning custom-block"><p class="custom-block-title">DEVELOPER REQUIRED</p><p>The following Branch Email prerequisites involve app code changes:</p><ul><li><a href="./native-sdks-overview.html"><strong>Implement the Branch SDK</strong></a></li><li><a href="./ios-universal-links.html"><strong>Enable Universal Linking</strong></a></li><li><a href="./ios-basic-integration.html"><strong>Add Your ESP’s CTD to Your Associated Domains Entitlement</strong></a></li><li><a href="./ios-advanced-features.html#web-only-content"><strong>Add Handle Web-Only Content App Code</strong></a></li><li><a href="./ios-full-reference.html#continueuseractivity"><strong>Add Return YES to continueUserActivity</strong></a></li></ul></div><h2 id="_2-configure-salesforce" tabindex="-1">2. Configure Salesforce <a class="header-anchor" href="#_2-configure-salesforce" aria-label="Permalink to &quot;2. Configure Salesforce&quot;">​</a></h2><p><strong>Secure your Salesforce Click Tracking Domain</strong></p><p>If your click tracking domain is not secure (i.e., secure domains will start with <code>https://</code>), you will need to purchase an SSL SKU from your Salesforce Account Manager.</p><p><strong>NOTE</strong>: Please keep in mind Salesforce can take 4-6 weeks to process SSL certificate requests.</p><p><strong>Configure your AASA file in Salesforce Marketing Cloud</strong></p><p>Your Salesforce account must be configured to correctly handle Universal Links. Configure the settings in Deep Linking under the Send Management section in Email Studio. Ensure you&#39;re in the account corresponding to the correct click tracking domain.</p><p><em>[Image: image]</em>.png)</p><ol><li>Enter the AppID value</li><li>Check the &quot;Exclude Profile&quot; and &quot;Unsub Center&quot; checkboxes to force links to these items to open in the browser and not the app, if desired.</li><li>Click &quot;Save&quot; to save the configuration.</li><li>Let Salesforce and Branch know that you&#39;ve finished this step and your Technical Account Manager will verify that everything looks good.</li></ol><h2 id="_3-enable-the-integration" tabindex="-1">3. Enable the Integration <a class="header-anchor" href="#_3-enable-the-integration" aria-label="Permalink to &quot;3. Enable the Integration&quot;">​</a></h2><p>To enable the integration:</p><ol><li><p>In the left-hand navigation, click <strong>Email</strong>.</p></li><li><p>On the Email overview page, click the <strong>Manager</strong> tab at the top.</p></li><li><p>Find your ESP and click <strong>Enable</strong>.</p><p>.gif &quot;salesforce-open-web-enable.gif&quot;)</p></li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Branch automatically detects any global link settings you have already provided during the initial setup of your Branch account as outlined above.</p><p>If you have not set up your <a href="./configure-default-link-behaviors.html">global link settings and redirect preferences</a>, you will be prompted to do so at this time.</p></div><h2 id="_4-provide-click-tracking-domain" tabindex="-1">4. Provide Click Tracking Domain <a class="header-anchor" href="#_4-provide-click-tracking-domain" aria-label="Permalink to &quot;4. Provide Click Tracking Domain&quot;">​</a></h2><p>Click tracking domains allow you to track engagement on email opens and link clicks.</p><p>If you&#39;re unsure what your click tracking domain (CTD) is, take a look at one of your recently sent emails. If you hover over the link or right-click/copy the link address, you will see that the domain of the link in the email does not match the URL in your HTML. This domain is your click tracking domain used by your ESP to provide you click reporting.</p><p>The Salesforce v1 Open App Default integration requires you provide the following:</p><ul><li><strong>Click Tracking Domain</strong> - The domain you use with Salesforce for links in emails</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Remove <code>http://</code> or <code>https://</code> when adding your click tracking domain in the Branch dashboard</p></div><p><em>[Image: 2394]</em>.png &quot;Screen Shot 2020-11-13 at 1.02.21 PM.png&quot;)</p><p><strong>KEEP IN MIND</strong></p><ul><li>You can enable the integration with multiple CTD if needed, but you cannot add the same CTD to multiple Branch dashboards or ESP integrations.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Before you click <strong>NEXT</strong> and proceed to the <strong>Validate &amp; Test</strong> section, please complete the following section as it’s required for passing integration validation.</p></div><h2 id="_5-validate-the-integration" tabindex="-1">5. Validate the Integration <a class="header-anchor" href="#_5-validate-the-integration" aria-label="Permalink to &quot;5. Validate the Integration&quot;">​</a></h2><p>Once the SSL certificates and AASA file (iOS only) have been generated, you can proceed to reviewing the validation tests, fix any issues and then test the integration.</p><p>Branch automatically validates the following:</p><ul><li>iOS SDK is integrated (required)</li><li>Android SDK is integrated (required)</li><li>Deep linking is setup (required)</li><li>Click Tracking Domain is setup (required)</li><li>AASA file is valid (required)</li><li>SSL is correctly setup (required)</li><li>CNAME points to thirdparty.bnc.lt (case-by-case requirement)</li><li>Universal Linking is setup (required)</li><li>Hosted deep link data (optional)</li><li>App Events being tracked (optional)</li><li>Android App Links (optional)</li></ul><p>.png &quot;setup-verification.png&quot;)</p><div class="warning custom-block"><p class="custom-block-title">Common Validation Issues</p><p><strong>CNAME Does Not Point to Branch</strong></p><p>As this integration requires the CNAME to point to Salesforce, you will always get this error. You can safely ignore.</p><hr><p><strong>SSL Not Correctly Set Up</strong></p><p>If you are having issues with the SSL certificate validating, the culprit is generally the fact that your click tracking domain already has SSL set up and there are restrictions that prevent a 3rd party from submitting a Certificate Signing Request on your behalf.</p><p><strong>AASA File is Invalid</strong></p><p>Luckily the easiest issue to fix as the main reason for this error is the fact that it depends on the SSL being set up correctly. By addressing the SSL error, the AASA file error should resolve itself simultaneously.</p></div><h2 id="_6-test-the-integration" tabindex="-1">6. Test the Integration <a class="header-anchor" href="#_6-test-the-integration" aria-label="Permalink to &quot;6. Test the Integration&quot;">​</a></h2><p>Once the validation process is complete, you can test the integration by generating a test link. The test link generated by Branch is unique in that it’s already converted to a Branch link for you and allows you to test without creating an email template in your ESP. In reality, this conversion happens behind the scenes once a user clicks on your normal email template link.</p><p>To generate a test link:</p><ol><li>In the <strong>Validate &amp; Test</strong> section, input a URL from your website.</li><li>Click <strong>Get Test Link</strong>.</li><li>Once the Test Link is generated, you can share it via:</li><li>Copy to clipboard</li><li>SMS</li><li>Email</li></ol><p>.gif &quot;test-link.gif&quot;)</p><p>Once you’ve generated your test link, click the link on your mobile device; don’t forget to make sure your mobile device already has the app installed!</p><h2 id="_7-generating-branch-links-for-email" tabindex="-1">7. Generating Branch Links for Email <a class="header-anchor" href="#_7-generating-branch-links-for-email" aria-label="Permalink to &quot;7. Generating Branch Links for Email&quot;">​</a></h2><p><strong>1. Use Salesforce AMPscript to convert links</strong></p><p>Using Salesforce&#39;s AMPscript, we&#39;ll add a new Content Area in Salesforce that converts web links in your email templates into Branch Links.</p><ol><li><p>Work with your Branch account manager to modify the following Salesforce AMPscript snippet, replacing <code>DOMAIN-HERE</code> with your Branch base domain (i.e., example.app.link):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%%[ VAR @deeplink, @branch_base_url SET @branch_base_url = &quot;https://DOMAIN-HERE/3p?%243p=e_et&quot; SET @deeplink = CONCAT(@branch_base_url, CONCAT(&quot;&amp;%24original_url=&quot;, URLEncode(@link_to_be_wrapped, 1, 1))) ]%%</span></span></code></pre></div></li><li><p>After logging into Salesforce Marketing Cloud, click on <strong>Email Studio</strong> and then a sub-menu will appear. Click on <strong>Email</strong> in the dropdown menu:</p><p>.png &quot;Screen Shot 2020-12-11 at 9.34.42 AM.png&quot;)</p></li><li><p>This will take you to the landing page for the Email section. Click on <strong>Content</strong> in the menu bar to navigate to the Content section:</p><p>.png &quot;content.png&quot;)</p></li><li><p>In the Content section, you will see a list of folders on the left side. Right click on the <strong>My Contents</strong> folder and choose <strong>Create Folder</strong> in the content builder menu:</p><p>.png &quot;Screen Shot 2020-12-11 at 9.35.50 AM.png&quot;)</p></li><li><p>Name the folder <code>Branch</code>:</p><p>.png &quot;Screen Shot 2020-12-11 at 9.36.09 AM.png&quot;)</p></li><li><p>Once the folder is created, in the upper right side, click on <strong>Create</strong> button, then click <strong>Content Blocks</strong> and finally click <strong>Free Form</strong>:</p><p>.png &quot;Screen Shot 2020-12-11 at 9.36.55 AM.png&quot;)</p></li><li><p>On the <strong>Free Form</strong> screen, paste in the snippet you previouisly generated:</p><p>.png &quot;Screen Shot 2020-12-11 at 9.38.50 AM.png&quot;)</p></li><li><p>Click <strong>Save</strong>.</p></li><li><p>In the <strong>Create Free Form</strong> window that appears, enter <code>deeplink</code> in the text field named Content Name. Click on <strong>Save</strong> after you enter the text:</p><p>.png &quot;Screen Shot 2020-12-11 at 9.39.04 AM.png&quot;)</p></li><li><p>You will now be back at your list of folders in the Content section with the file <strong>deeplink</strong> listed:</p></li></ol><p>You have now successfully created the deep linking AMPscript.</p><div class="info custom-block"><p class="custom-block-title">Code snippet</p><p>The snippet below will follow this format. The code below also has a placeholder for <code>@branch_base_url</code>. Replace it with yours.</p></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%%[ VAR @deeplink, @branch_base_url SET @branch_base_url = &quot;BASE URL FROM BRANCH&quot; SET @deeplink = CONCAT(@branch_base_url, CONCAT(&quot;&amp;%24original_url=&quot;, URLEncode(@link_to_be_wrapped, 1, 1))) ]%%</span></span></code></pre></div><p><strong>Configure your Salesforce email templates</strong></p><p>This section covers how to convert individual links in your existing email templates into Branch deep links. You will need to do this for all links in your email template that you want to convert to Branch deep links.</p><p>For example, if you decide to convert the link below into a Branch Link:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;a href=&quot;https://branch.io/product/1234/&quot;&gt; I want it! &lt;/a&gt;</span></span></code></pre></div><p>This is what the link will look like in the email template, <strong>after</strong> you added the AMPscript to convert it into a Branch link:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%%[ SET @link_to_be_wrapped = &quot;https://branch.io/product/1234/&quot; ContentAreaByName(&quot;My Contents\\branch\\deeplink&quot;) ]%%</span></span>
<span class="line"><span>&lt;a href=&quot;%%=RedirectTo(@deeplink)=%%&quot;&gt;Example link&lt;/a&gt;</span></span></code></pre></div><p>The process to convert links into Branch Links using AMPscript is as follows (this flow converts the links in a separate document, and then pastes them back into your final template):</p><ol><li><p>Log in to Salesforce Marketing Cloud</p></li><li><p>Click on <strong>Email Studio</strong> and then a sub-menu will appear. Click on <strong>Email</strong> in the dropdown menu:</p><p><em>[Image: image]</em>.png)</p></li><li><p>This will take you to the landing page for the Email section. Click on <strong>Content</strong> in the menu bar to navigate to the Content section:</p><p><em>[Image: image]</em>.png)</p></li><li><p>Navigate to your folder containing your emails and open an existing email. Make sure the email is in HTML layout as shown below:</p><p><em>[Image: image]</em>.png)</p></li><li><p>Choose a link that you want to convert to a Branch deep link. Copy the text right after the <code>href=</code> in your email template, and paste it into a separate document. In the example, it is:</p><p><code>&quot;https://branch.io/product/1234/&quot;</code></p></li><li><p>Add <code>%%[ SET @link_to_be_wrapped =</code> before the link in your separate document. In the example, this is now:</p><p><code>%%[ SET @link_to_be_wrapped = &quot;https://branch.io/product/1234/&quot;</code></p></li><li><p>Add <code>ContentAreaByName(&quot;My Contents\\branch\\deeplink&quot;&quot;)]%%</code> after the link:</p><p><code>%%[ SET @link_to_be_wrapped = &quot;https://branch.io/product/1234/&quot;ContentAreaByName(&quot;My Contents\\branch\\deeplink&quot;&quot;)]%%</code></p></li><li><p>From the original link in your template, copy the text from and including <code>&lt;a</code> until the <code>href=</code>. Add it to the text after <code>%%</code> in the last step. Please include the <code>&lt;a</code> but not the <code>href=</code>:</p><p><code>%%[ SET @link_to_be_wrapped = &quot;https://branch.io/product/1234/&quot; ContentAreaByName(&quot;My Contents\\branch\\deeplink&quot;&quot;) ]%% &lt;a style=&quot;_any css can be added here_&quot;</code></p></li><li><p>Add <code>href=&quot;%%=RedirectTo(@deeplink)=%%&quot;</code> to the end:</p><p><code>%%[ SET @link_to_be_wrapped = &quot;https://branch.io/product/1234/&quot; ContentAreaByName(&quot;My Contents\\branch\\deeplink&quot;&quot;) ]%% &lt;a style=&quot;_any css can be added here_&quot;href=&quot;%%=RedirectTo(@deeplink)=%%&quot;</code></p></li><li><p>From the original link in your template, copy the end of the tag, the link text, and the closing tag (<code>&gt;I want it!</code> in the example) and add it to the end:</p><p><code>%%[ SET @link_to_be_wrapped = &quot;https://branch.io/product/1234/&quot; ContentAreaByName(&quot;My Contents\\branch\\deeplink&quot;&quot;) ]%% &lt;a style=&quot;_any css can be added here_&quot; href=&quot;%%=RedirectTo(@deeplink)=%%&quot;&gt;I want it!&lt;/a&gt;</code></p></li><li><p>Copy your final result from the separate document back into your email template, replacing everything inside and including the <code>&lt;a&gt;&lt;/a&gt;</code> tags in the template.</p></li><li><p>Repeat this for all your links in your email template that you want to convert to Branch deep links.</p></li></ol><div class="info custom-block"><p class="custom-block-title">Link Conversion Summary</p><p>Wherever you use <code>&lt;a&gt;</code> tags in your email templates, replace those with AMPscript to convert the web URLs into Branch Links. The AMPscript references the <a href="#add-a-new-content-area-for-easy-deep-linking">Content Area</a> setup earlier.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%%[SET @link_to_be_wrapped = &quot;ADD YOUR LINK HERE&quot; ContentAreaByName(&quot;My Contents\\branch\\deeplink&quot;)]%%</span></span>
<span class="line"><span>&lt;a href=&quot;%%=RedirectTo(@deeplink)=%%&quot;&gt;Click Me&lt;/a&gt;</span></span></code></pre></div><p>For example,<br><strong>Before:</strong><br><code>&lt;a href=&quot;https://branch.io/product/1234&quot;&gt;Example link&lt;/a&gt;</code><br><strong>After:</strong><br><code>%%[ SET @link_to_be_wrapped = &quot;https://branch.io/product/1234&quot; ContentAreaByName(&quot;My Contents\\deeplink&quot;) ]%%</code></p><p><code>&lt;a href=&quot;%%=RedirectTo(@deeplink)=%%&quot;&gt;Example link&lt;/a&gt;</code></p></div><div class="warning custom-block"><p class="custom-block-title">Content Area Folder</p><p>Make sure your <code>deeplink</code> Content Area is in the right folder. Either change the folder to &quot;My Contents&quot; or change the path used by &quot;ContentAreaByName&quot; in the Branch script.</p></div><p><strong>2. Making regular Branch Links compatible with email</strong></p><p>Be sure to add <code>&quot;$3p&quot;:&quot;e_et&quot;</code> to the deep link data of any links you use in email to ensure Universal Link and click tracking works as expected.</p><p><strong>3. Create email links via API</strong></p><p>To create email links via API, please use the instructions on how to <a href="./deep-linking-api.html">create links via API</a>, but include the following key value pairs in your call:</p><ol><li><code>&quot;$3p&quot;:&quot;e_et&quot;</code> This is required for Universal Link and click tracking functionality.</li><li><code>&quot;$original_url&quot;:&quot;&amp;#123;&amp;#123;your web url URI encoded&amp;#125;&amp;#125;&quot;</code> For each piece of content, include a URI encoded version of your content&#39;s web URL. You can also add deep link data as query parameters on that web URL. This ensures accurate Content Analytics reporting.<br><strong>Example:</strong> <code>&quot;$original_url&quot;:&quot;https%3A%2F%2Fshop.com%2Fshoes%2Fbrown-shoes%3Fmy_key%3Dmy_value%26campaign%3Dshoe_discounts&quot;</code></li></ol><p>Here is how links look before and after (the latter being a Branch deep link).</p><ol><li><em>Before:</em> <a href="http://example.com/?foo=bar" target="_blank" rel="noreferrer">http://example.com/?foo=bar</a></li><li><em>After:</em> <a href="https://vza3.app.link/3p?%243p=e_xx&amp;%24original_url=http%3A%2F%2Fexample.com%2F%3Ffoo%3Dbar" target="_blank" rel="noreferrer">https://vza3.app.link/3p?%243p=e_xx&amp;%24original_url=http%3A%2F%2Fexample.com%2F%3Ffoo%3Dbar</a></li></ol><p><strong>Note</strong> that these are simplified examples, not actual demo links.</p><p><strong>4. Flag your web-only links</strong></p><p>For links that should always open in web, even if the app is installed, add Salesforce&#39;s link attribute <code>mc-deep-link=&quot;false&quot;</code> to your link tag to ensure the app does not open in iOS:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;a mc-deep-link=&quot;false&quot; href=&quot;https://my.app.link/3p?$3p=e_et&amp;$original_url=...&quot; &gt; This link will not open the app. &lt;/a&gt;</span></span></code></pre></div><p>If the link in the &quot;href&quot; part of the tag is a normal web link, the app will NOT open in Android. If the link in the &quot;href&quot; part of the tag is a Branch link, but you don&#39;t want the app to open, then you&#39;ll need to add <code>&amp;%24web_only%3Dtrue</code> as a query parameter:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;a href=&quot;https://my.app.link/3p?%243p=e_xx&amp;%24original_url=http%3A%2F%2Fexample.com&amp;%24web_only%3Dtrue&quot; &gt; This link will not open the app. &lt;/a&gt;</span></span></code></pre></div>`,69)])])}const g=t(a,[["render",l]]);export{h as __pageData,g as default};
